/// AI Intelligence Module — Insights, document processing, and search embeddings
///
/// # Tables
/// | Table | Description |
/// |-------|-------------|
/// | **AiInsight** | Business intelligence insights generated by AI agents |
/// | **AiDocumentProcessingJob** | OCR / extraction / classification jobs |
/// | **SearchEmbedding** | Vector embeddings for semantic search |
use spacetimedb::{reducer, Identity, ReducerContext, Table, Timestamp};

use crate::helpers::{check_permission, write_audit_log};
use crate::types::{InsightSeverity, JobStatus};

// ============================================================================
// TABLES
// ============================================================================

/// AiInsight — A business intelligence finding generated by an AI agent
#[derive(Clone)]
#[spacetimedb::table(
    accessor = ai_insight,
    public,
    index(name = "by_model", accessor = insight_by_model, btree(columns = [related_model])),
    index(name = "by_company", accessor = insight_by_company, btree(columns = [company_id]))
)]
pub struct AiInsight {
    #[primary_key]
    #[auto_inc]
    pub id: u64,

    pub severity: InsightSeverity,
    pub title: String,
    pub description: String,
    pub recommendations: Vec<String>,
    pub related_model: String,        // e.g., "sale_order", "inventory"
    pub related_id: Option<u64>,
    pub confidence: f64,              // 0.0–1.0
    pub generated_at: Timestamp,
    pub generated_by: Option<u64>,    // AI Agent ID
    pub is_acknowledged: bool,
    pub acknowledged_by: Option<Identity>,
    pub acknowledged_at: Option<Timestamp>,
    pub dismissed: bool,
    pub dismissed_by: Option<Identity>,
    pub dismissed_at: Option<Timestamp>,
    pub action_taken: Option<String>,
    pub impact_score: Option<f64>,
    pub priority: Option<u8>,
    pub tags: Vec<String>,
    pub company_id: Option<u64>,
    pub create_uid: Identity,
    pub create_date: Timestamp,
    pub write_uid: Identity,
    pub write_date: Timestamp,
    pub metadata: Option<String>,
}

/// AiDocumentProcessingJob — AI-powered document OCR, extraction, or classification
#[derive(Clone)]
#[spacetimedb::table(
    accessor = ai_document_processing_job,
    public,
    index(name = "by_status", accessor = doc_job_by_status, btree(columns = [status])),
    index(name = "by_company", accessor = doc_job_by_company, btree(columns = [company_id]))
)]
pub struct AiDocumentProcessingJob {
    #[primary_key]
    #[auto_inc]
    pub id: u64,

    pub document_type: String,                    // Invoice, Receipt, Contract, etc.
    pub job_type: String,                         // OCR, Extraction, Classification, Analysis
    pub status: JobStatus,
    pub ai_agent_id: Option<u64>,
    pub model_used: Option<String>,
    pub input_data: Option<String>,               // JSON — source document reference
    pub extracted_data: Option<String>,           // JSON — extracted fields
    pub confidence_score: Option<f64>,
    pub error_message: Option<String>,
    pub processing_started_at: Option<Timestamp>,
    pub processing_completed_at: Option<Timestamp>,
    pub tokens_used: Option<u32>,
    pub cost: Option<f64>,
    pub reviewed_by: Option<Identity>,
    pub reviewed_at: Option<Timestamp>,
    pub is_approved: bool,
    pub company_id: Option<u64>,
    pub create_uid: Identity,
    pub create_date: Timestamp,
    pub write_uid: Identity,
    pub write_date: Timestamp,
    pub metadata: Option<String>,
}

/// SearchEmbedding — Vector embedding for a piece of content (semantic search)
#[spacetimedb::table(
    accessor = search_embedding,
    public,
    index(name = "by_content", accessor = embedding_by_content, btree(columns = [content_type])),
    index(name = "by_company", accessor = embedding_by_company, btree(columns = [company_id]))
)]
pub struct SearchEmbedding {
    #[primary_key]
    #[auto_inc]
    pub id: u64,

    pub content_type: String,         // product, contact, document, article, etc.
    pub content_id: u64,
    pub text: String,                 // Original text that was embedded
    pub embedding: Vec<f32>,          // Vector embedding values
    pub embedding_hash: Option<String>, // Hash of text for change detection
    pub company_id: Option<u64>,
    pub create_uid: Identity,
    pub create_date: Timestamp,
    pub write_uid: Identity,
    pub write_date: Timestamp,
    pub metadata: Option<String>,
}

// ============================================================================
// REDUCERS
// ============================================================================

/// Create an AI insight (typically called by an AI integration process)
#[reducer]
pub fn create_ai_insight(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    severity: InsightSeverity,
    title: String,
    description: String,
    recommendations: Vec<String>,
    related_model: String,
    related_id: Option<u64>,
    confidence: f64,
    generated_by: Option<u64>,
    tags: Vec<String>,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_insight", "create")?;

    if confidence < 0.0 || confidence > 1.0 {
        return Err("Confidence must be between 0.0 and 1.0".to_string());
    }

    let insight = ctx.db.ai_insight().insert(AiInsight {
        id: 0,
        severity,
        title,
        description,
        recommendations,
        related_model,
        related_id,
        confidence,
        generated_at: ctx.timestamp,
        generated_by,
        is_acknowledged: false,
        acknowledged_by: None,
        acknowledged_at: None,
        dismissed: false,
        dismissed_by: None,
        dismissed_at: None,
        action_taken: None,
        impact_score: None,
        priority: None,
        tags,
        company_id,
        create_uid: ctx.sender(),
        create_date: ctx.timestamp,
        write_uid: ctx.sender(),
        write_date: ctx.timestamp,
        metadata: None,
    });

    write_audit_log(
        ctx,
        cid,
        None,
        "ai_insight",
        insight.id,
        "create",
        None,
        None,
        vec!["created".to_string()],
    );

    log::info!("AI insight created: id={}, severity={:?}", insight.id, insight.severity);
    Ok(())
}

/// Acknowledge an AI insight
#[reducer]
pub fn acknowledge_insight(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    insight_id: u64,
    action_taken: Option<String>,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_insight", "write")?;

    let insight = ctx
        .db
        .ai_insight()
        .id()
        .find(&insight_id)
        .ok_or("Insight not found")?;

    if insight.is_acknowledged {
        return Ok(()); // Idempotent
    }

    ctx.db.ai_insight().id().update(AiInsight {
        is_acknowledged: true,
        acknowledged_by: Some(ctx.sender()),
        acknowledged_at: Some(ctx.timestamp),
        action_taken,
        write_uid: ctx.sender(),
        write_date: ctx.timestamp,
        ..insight
    });

    write_audit_log(
        ctx,
        cid,
        None,
        "ai_insight",
        insight_id,
        "write",
        None,
        None,
        vec!["acknowledged".to_string()],
    );

    log::info!("AI insight acknowledged: id={}", insight_id);
    Ok(())
}

/// Dismiss an AI insight
#[reducer]
pub fn dismiss_insight(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    insight_id: u64,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_insight", "write")?;

    let insight = ctx
        .db
        .ai_insight()
        .id()
        .find(&insight_id)
        .ok_or("Insight not found")?;

    if insight.dismissed {
        return Ok(()); // Idempotent
    }

    ctx.db.ai_insight().id().update(AiInsight {
        dismissed: true,
        dismissed_by: Some(ctx.sender()),
        dismissed_at: Some(ctx.timestamp),
        write_uid: ctx.sender(),
        write_date: ctx.timestamp,
        ..insight
    });

    write_audit_log(
        ctx,
        cid,
        None,
        "ai_insight",
        insight_id,
        "write",
        None,
        None,
        vec!["dismissed".to_string()],
    );

    log::info!("AI insight dismissed: id={}", insight_id);
    Ok(())
}

/// Submit a new document processing job
#[reducer]
pub fn create_document_processing_job(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    document_type: String,
    job_type: String,
    ai_agent_id: Option<u64>,
    input_data: Option<String>,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_document_processing_job", "create")?;

    let job = ctx.db.ai_document_processing_job().insert(AiDocumentProcessingJob {
        id: 0,
        document_type,
        job_type,
        status: JobStatus::Pending,
        ai_agent_id,
        model_used: None,
        input_data,
        extracted_data: None,
        confidence_score: None,
        error_message: None,
        processing_started_at: None,
        processing_completed_at: None,
        tokens_used: None,
        cost: None,
        reviewed_by: None,
        reviewed_at: None,
        is_approved: false,
        company_id,
        create_uid: ctx.sender(),
        create_date: ctx.timestamp,
        write_uid: ctx.sender(),
        write_date: ctx.timestamp,
        metadata: None,
    });

    write_audit_log(
        ctx,
        cid,
        None,
        "ai_document_processing_job",
        job.id,
        "create",
        None,
        None,
        vec!["submitted".to_string()],
    );

    log::info!(
        "Document processing job created: id={}, type={}/{}",
        job.id,
        job.document_type,
        job.job_type
    );
    Ok(())
}

/// Update the result of a document processing job
#[reducer]
pub fn complete_document_processing_job(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    job_id: u64,
    extracted_data: Option<String>,
    confidence_score: Option<f64>,
    model_used: Option<String>,
    tokens_used: Option<u32>,
    cost: Option<f64>,
    error_message: Option<String>,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_document_processing_job", "write")?;

    let job = ctx
        .db
        .ai_document_processing_job()
        .id()
        .find(&job_id)
        .ok_or("Processing job not found")?;

    let status = if error_message.is_some() {
        JobStatus::Failed
    } else {
        JobStatus::Completed
    };

    ctx.db
        .ai_document_processing_job()
        .id()
        .update(AiDocumentProcessingJob {
            status,
            extracted_data,
            confidence_score,
            model_used,
            tokens_used,
            cost,
            error_message,
            processing_completed_at: Some(ctx.timestamp),
            write_uid: ctx.sender(),
            write_date: ctx.timestamp,
            ..job
        });

    write_audit_log(
        ctx,
        cid,
        None,
        "ai_document_processing_job",
        job_id,
        "write",
        None,
        None,
        vec!["completed".to_string()],
    );

    log::info!("Document processing job completed: id={}", job_id);
    Ok(())
}

/// Approve extracted data from a processing job
#[reducer]
pub fn approve_document_processing_job(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    job_id: u64,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "ai_document_processing_job", "write")?;

    let job = ctx
        .db
        .ai_document_processing_job()
        .id()
        .find(&job_id)
        .ok_or("Processing job not found")?;

    if job.status != JobStatus::Completed {
        return Err("Job must be completed before approval".to_string());
    }

    ctx.db
        .ai_document_processing_job()
        .id()
        .update(AiDocumentProcessingJob {
            is_approved: true,
            reviewed_by: Some(ctx.sender()),
            reviewed_at: Some(ctx.timestamp),
            write_uid: ctx.sender(),
            write_date: ctx.timestamp,
            ..job
        });

    write_audit_log(
        ctx,
        cid,
        None,
        "ai_document_processing_job",
        job_id,
        "write",
        None,
        None,
        vec!["approved".to_string()],
    );

    log::info!("Document processing job approved: id={}", job_id);
    Ok(())
}

/// Upsert a search embedding for a piece of content
#[reducer]
pub fn upsert_search_embedding(
    ctx: &ReducerContext,
    company_id: Option<u64>,
    content_type: String,
    content_id: u64,
    text: String,
    embedding: Vec<f32>,
    embedding_hash: Option<String>,
) -> Result<(), String> {
    let cid = company_id.unwrap_or(0);
    check_permission(ctx, cid, "search_embedding", "create")?;

    if embedding.is_empty() {
        return Err("Embedding vector cannot be empty".to_string());
    }

    // Check if an embedding already exists for this content
    let existing: Option<SearchEmbedding> = ctx
        .db
        .search_embedding()
        .embedding_by_content()
        .filter(&content_type)
        .find(|e| e.content_id == content_id && e.company_id == company_id);

    if let Some(existing) = existing {
        ctx.db.search_embedding().id().update(SearchEmbedding {
            text,
            embedding,
            embedding_hash,
            write_uid: ctx.sender(),
            write_date: ctx.timestamp,
            ..existing
        });
        log::info!(
            "Search embedding updated: content_type={}, content_id={}",
            content_type,
            content_id
        );
    } else {
        ctx.db.search_embedding().insert(SearchEmbedding {
            id: 0,
            content_type: content_type.clone(),
            content_id,
            text,
            embedding,
            embedding_hash,
            company_id,
            create_uid: ctx.sender(),
            create_date: ctx.timestamp,
            write_uid: ctx.sender(),
            write_date: ctx.timestamp,
            metadata: None,
        });
        log::info!(
            "Search embedding created: content_type={}, content_id={}",
            content_type,
            content_id
        );
    }

    Ok(())
}
